+                            }
+                            grad_lhs_elems[lhs_idx] += g_acc;
+                        }
+                    }
+                }
+            }
+        }
+    }
+
+    make_conv_grad_pair(&lhs.shape, &rhs.shape, grad_lhs_elems, grad_rhs_elems)
+}
+
+fn make_conv_grad_pair(
+    lhs_shape: &Shape,
+    rhs_shape: &Shape,
+    grad_lhs_elems: Vec<f64>,
+    grad_rhs_elems: Vec<f64>,
