+            DType::F64,
+            rhs_shape.clone(),
+            grad_rhs_elems.into_iter().map(Literal::from_f64).collect(),
+        )
+        .map_err(|e| AdError::EvalFailed(e.to_string()))?,
+    );
+    Ok(vec![grad_lhs, grad_rhs])
